'use client'
import { cn } from '@cascivo/core'
import type { CSSProperties, HTMLAttributes } from 'react'
import styles from './skeleton.module.css'

export interface SkeletonProps extends HTMLAttributes<HTMLDivElement> {
  variant?: 'text' | 'circle' | 'rect'
  width?: string
  height?: string
  lines?: number
}

export function Skeleton({
  variant = 'text',
  width,
  height,
  lines = 1,
  className,
  style,
  ...props
}: SkeletonProps) {
  const sizeVars = {
    ...(width !== undefined && { '--cascivo-skeleton-width': width }),
    ...(height !== undefined && { '--cascivo-skeleton-height': height }),
  } as CSSProperties

  return (
    <div
      aria-hidden="true"
      data-variant={variant}
      className={cn(styles['skeleton'], className)}
      style={{ ...sizeVars, ...style }}
      {...props}
    >
      {variant === 'text' &&
        Array.from({ length: lines }, (_, index) => (
          <span key={index} className={styles['line']} />
        ))}
    </div>
  )
}

@layer cascivo.component {
  .skeleton {
    &[data-variant='text'] {
      display: flex;
      flex-direction: column;
      gap: var(--cascivo-space-2);
      inline-size: var(--cascivo-skeleton-width, 100%);
    }

    &[data-variant='circle'] {
      inline-size: var(--cascivo-skeleton-width, var(--cascivo-space-10));
      block-size: var(--cascivo-skeleton-height, var(--cascivo-space-10));
      border-radius: var(--cascivo-radius-full);
    }

    &[data-variant='rect'] {
      inline-size: var(--cascivo-skeleton-width, 100%);
      block-size: var(--cascivo-skeleton-height, var(--cascivo-space-24));
      border-radius: var(--cascivo-radius-surface);
    }
  }

  .line {
    display: block;
    inline-size: 100%;
    block-size: var(--cascivo-skeleton-height, 1em);
    border-radius: var(--cascivo-radius-indicator);

    /* Multi-line paragraphs end on a shorter bar */
    &:last-child:not(:first-child) {
      inline-size: 60%;
    }
  }

  /* Continuous shimmer — literal duration; a static fallback below
     replaces the duration-token opt-out used for one-shot motion. */
  .skeleton[data-variant='circle'],
  .skeleton[data-variant='rect'],
  .line {
    background-color: var(--cascivo-color-border);
    background-image: linear-gradient(
      90deg,
      var(--cascivo-color-border) 25%,
      var(--cascivo-color-bg-subtle) 50%,
      var(--cascivo-color-border) 75%
    );
    background-size: 200% 100%;
    animation: cascade-shimmer 1.5s linear infinite;
  }

  @keyframes cascade-shimmer {
    from {
      background-position: 200% 0;
    }

    to {
      background-position: -200% 0;
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .skeleton[data-variant='circle'],
    .skeleton[data-variant='rect'],
    .line {
      animation: none;
      background-image: none;
    }
  }
}
